import java.io.IOException;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        response.setContentType("text/html");
        response.getWriter().write("<html><body>");
        try {
            String safeUserInput = ESAPI.encoder().encodeForHTML(userInput);
            response.getWriter().write("<h1>User Input: " + safeUserInput + "</h1>");
        } catch (EncodingException e) {
            // Handle encoding exception
            response.getWriter().write("<h1>Error processing user input</h1>");
        }
        response.getWriter().write("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
